g__call_goals(A,prolog(B),C):-m__body__(call_goals(A,prolog(B),C),C=m__body__(A,B)).
g__call_goals(A,call(B),C):-m__body__(call_goals(A,call(B),C),C=m__body__(A,m__call__(B))).
