g__rename_term(A,B):-m__body__(rename_term(A,B),A=..[C|D]),!,m__body__(rename_term(A,B),g__atom_concat(g__,C,E)),!,m__body__(rename_term(A,B),B=..[E|D]).
g__preprocess_dcg([],[]).
g__preprocess_dcg([term_data(A,B)|C],[term_data(D,B)|E]):-m__body__(preprocess_dcg([term_data(A,B)|C],[term_data(D,B)|E]),
		  g__preprocess_dcg_term(A,D)),!,m__body__(preprocess_dcg([term_data(A,B)|C],[term_data(D,B)|E]),
		  g__preprocess_dcg(C,E)).
g__preprocess_dcg_term((A-->B|C),D):-( m__guard__(preprocess_dcg_term((A-->B|C),D),E=(A-->B|C)),
  m__guard__(preprocess_dcg_term((A-->B|C),D),g__may_be_stream(B)),
  m__guard__(preprocess_dcg_term((A-->B|C),D),g__may_be_stream(C))
),!,m__body__(preprocess_dcg_term((A-->B|C),D),
		  g__throw(error(invalid_predicate(E)))).
g__preprocess_dcg_term((A-->B|C),(D:-E|F)):-( m__guard__(preprocess_dcg_term((A-->B|C),(D:-E|F)),G=(A-->B|C)),
  m__guard__(preprocess_dcg_term((A-->B|C),(D:-E|F)),
			 g__may_be_stream(B))
),!,m__body__(preprocess_dcg_term((A-->B|C),(D:-E|F)),
		  g__preprocess_dcg_stream(G,B,H-I,E)),!,m__body__(preprocess_dcg_term((A-->B|C),(D:-E|F)),A=..[J|K]),!,m__body__(preprocess_dcg_term((A-->B|C),(D:-E|F)),g__append(K,[H,I],L)),!,m__body__(preprocess_dcg_term((A-->B|C),(D:-E|F)),D=..[J|L]),!,m__body__(preprocess_dcg_term((A-->B|C),(D:-E|F)),F=C).
g__preprocess_dcg_term((A-->B|C),(D:-E|F)):-( m__guard__(preprocess_dcg_term((A-->B|C),(D:-E|F)),G=(A-->B|C)),
  m__guard__(preprocess_dcg_term((A-->B|C),(D:-E|F)),
			 g__may_be_stream(C))
),!,m__body__(preprocess_dcg_term((A-->B|C),(D:-E|F)),
		  g__preprocess_dcg_stream(G,C,H-I,F)),!,m__body__(preprocess_dcg_term((A-->B|C),(D:-E|F)),A=..[J|K]),!,m__body__(preprocess_dcg_term((A-->B|C),(D:-E|F)),g__append(K,[H,I],L)),!,m__body__(preprocess_dcg_term((A-->B|C),(D:-E|F)),D=..[J|L]),!,m__body__(preprocess_dcg_term((A-->B|C),(D:-E|F)),E=B).
g__preprocess_dcg_term((A-->B),(C:-D)):-( m__guard__(preprocess_dcg_term((A-->B),(C:-D)),E=(A-->B)),
  m__guard__(preprocess_dcg_term((A-->B),(C:-D)),g__may_be_stream(B))
),!,m__body__(preprocess_dcg_term((A-->B),(C:-D)),
		  g__preprocess_dcg_stream(E,B,F-G,D)),!,m__body__(preprocess_dcg_term((A-->B),(C:-D)),A=..[H|I]),!,m__body__(preprocess_dcg_term((A-->B),(C:-D)),g__append(I,[F,G],J)),!,m__body__(preprocess_dcg_term((A-->B),(C:-D)),C=..[H|J]).
g__preprocess_dcg_term(A,A).
g__may_be_stream(A):-( m__guard__(may_be_stream(A),g__may_be_stream(A,false,B)),
  m__guard__(may_be_stream(A),B=true)
),!,true.
g__may_be_stream(({A},B),C,D):-m__body__(may_be_stream(({A},B),C,D),D=true).
g__may_be_stream(([],A),B,C):-m__body__(may_be_stream(([],A),B,C),C=true).
g__may_be_stream(([A|B],C),D,E):-m__body__(may_be_stream(([A|B],C),D,E),E=true).
g__may_be_stream((A,B),C,D):-m__body__(may_be_stream((A,B),C,D),g__may_be_stream(B,C,D)).
g__may_be_stream({A},B,C) :- m__body__(may_be_stream({A},B,C),C=true).
g__may_be_stream([],A,B) :- m__body__(may_be_stream([],A,B),B=true).
g__may_be_stream([A|B],C,D) :- m__body__(may_be_stream([A|B],C,D),D=true).
g__may_be_stream(A,B,C) :- m__body__(may_be_stream(A,B,C),C=B).
g__preprocess_dcg_stream(A,(B,C),D-E,F):-m__guard__(preprocess_dcg_stream(A,(B,C),D-E,F),B=[]),!,m__body__(preprocess_dcg_stream(A,(B,C),D-E,F),
		  g__preprocess_dcg_stream(A,C,D-E,F)).
g__preprocess_dcg_stream(A,(B,C),D-E,(F,G)):-m__guard__(preprocess_dcg_stream(A,(B,C),D-E,(F,G)),B=[_|_]),!,m__body__(preprocess_dcg_stream(A,(B,C),D-E,(F,G)),
		  g__extend_list(B,H-I)),!,m__body__(preprocess_dcg_stream(A,(B,C),D-E,(F,G)),F=(D=H)),!,m__body__(preprocess_dcg_stream(A,(B,C),D-E,(F,G)),
		  g__preprocess_dcg_stream(A,C,I-E,G)).
g__preprocess_dcg_stream(A,(B,C),D-E,(F,G)):-m__guard__(preprocess_dcg_stream(A,(B,C),D-E,(F,G)),B={H}),!,m__body__(preprocess_dcg_stream(A,(B,C),D-E,(F,G)),F=H),!,m__body__(preprocess_dcg_stream(A,(B,C),D-E,(F,G)),
		  g__preprocess_dcg_stream(A,C,D-E,G)).
g__preprocess_dcg_stream(A,(B,C),D-E,(F,G)):-m__guard__(preprocess_dcg_stream(A,(B,C),D-E,(F,G)),B=..[H|I]),!,m__body__(preprocess_dcg_stream(A,(B,C),D-E,(F,G)),
		  g__append(I,[D,J],K)),!,m__body__(preprocess_dcg_stream(A,(B,C),D-E,(F,G)),F=..[H|K]),!,m__body__(preprocess_dcg_stream(A,(B,C),D-E,(F,G)),
		  g__preprocess_dcg_stream(A,C,J-E,G)).
g__preprocess_dcg_stream(A,B,C-D,E):-m__guard__(preprocess_dcg_stream(A,B,C-D,E),B=[]),!,m__body__(preprocess_dcg_stream(A,B,C-D,E),E=(C=D)).
g__preprocess_dcg_stream(A,B,C-D,E):-m__guard__(preprocess_dcg_stream(A,B,C-D,E),B=[_|_]),!,m__body__(preprocess_dcg_stream(A,B,C-D,E),g__extend_list(B,F-D)),!,m__body__(preprocess_dcg_stream(A,B,C-D,E),E=(C=F)).
g__preprocess_dcg_stream(A,B,C-D,E):-m__guard__(preprocess_dcg_stream(A,B,C-D,E),B={F}),!,m__body__(preprocess_dcg_stream(A,B,C-D,E),E=F),!,m__body__(preprocess_dcg_stream(A,B,C-D,E),C=D).
g__preprocess_dcg_stream(A,B,C-D,E):-m__guard__(preprocess_dcg_stream(A,B,C-D,E),B=..[F|G]),!,m__body__(preprocess_dcg_stream(A,B,C-D,E),g__append(G,[C,D],H)),!,m__body__(preprocess_dcg_stream(A,B,C-D,E),E=..[F|H]).
